// Decode a factor string into a flat Float32Array of cell values.
// The on-disk format uses a single character per cell from the
// extended legend
//   "_" = âˆ’2   "-" = âˆ’1   "." = 0   "+" = +1   "=" = +2
// â€” the underscore / equals pair is only used by the {âˆ’2..+2}
// preset rows; every other preset only emits "-" / "." / "+" so a
// decoder that ignores '_' and '=' would still get the {âˆ’1, 0, +1}
// subset right. We materialise into a Float32Array because the
// storage layer switched from Int8 to Float32 when half-integer /
// Â±2 alphabets were introduced (see tensor.ts).
export function decodeFactor(s: string): Float32Array {
	const out = new Float32Array(s.length);
	for (let i = 0; i < s.length; i++) {
		const c = s.charCodeAt(i);
		// '+' = 43, '-' = 45, '.' = 46, '_' = 95, '=' = 61
		// Fall through to 0 for any unrecognised character; this
		// shouldn't happen with our generated strings but keeps a
		// stray glyph from poisoning the whole board.
		out[i] =
			c === 43
				? 1
				: c === 45
					? -1
					: c === 95
						? -2
						: c === 61
							? 2
							: 0;
	}
	return out;
}

export function findAlphaTensorPreset(m: number, n: number, p: number): AlphaTensorPreset | null {
	return ALPHATENSOR_PRESETS.find((s) => s.m === m && s.n === n && s.p === p) ?? null;
}
